        Factory factory = model.getFactory();

        // Find all CtImport statements that might reference JaninoEventEvaluator
        List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));
        for (CtImport imp : imports) {
            if (imp.getReference() != null && 
                imp.getReference().getSimpleName().contains("JaninoEventEvaluator")) {
                // Remove the problematic import
                imp.getParent().removeStatement(imp);
            }
