import spoon.reflect.CtModel;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.factory.Factory;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

/**
 * Generic Spoon transformation to fix Logback 1.4.1 breaking changes
 * Specifically handles the removal of JaninoEventEvaluator due to CVE-2024-12798
 */
public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create the launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process
        launcher.addInputResource(sourceDirectory);

        // Set the output directory (same as input for in-place editing)
        launcher.setSourceOutputDirectory(sourceDirectory);

        // Build the model
        CtModel model = launcher.buildModel();

        // Apply fixes for Logback 1.4.1 breaking changes
        fixLogbackBreakingChanges(model, launcher.getFactory());

        // Write the updated code back
        launcher.writeProcessedSourceFiles();

        System.out.println("Logback 1.4.1 breaking change fixes applied successfully to " + sourceDirectory);
    }

    /**
     * Apply fixes for Logback 1.4.1 breaking changes
     */
    private static void fixLogbackBreakingChanges(CtModel model, Factory factory) {
        // Find and remove problematic imports
        List<CtImport> imports = model.getElements(new TypeFilter<>(CtImport.class));
        for (CtImport imp : imports) {
            String importReference = imp.getReference() != null ? imp.getReference().getQualifiedName() : "";
            if (importReference.contains("JaninoEventEvaluator") || 
                importReference.contains("ch.qos.logback.classic.boolex.JaninoEventEvaluator")) {
                // Remove the problematic import
                CtClass<?> parent = imp.getParent(CtClass.class);
                if (parent != null) {
                    parent.removeImport(imp);
                }
            }
        }

        System.out.println("Applied Logback 1.4.1 breaking change fixes");
    }
}

